import React from 'react';

function Experience({ data }) {
  if (!data) return null;

  return (
    <section id="experience" className="py-16 bg-gray-50">
      <div className="max-w-6xl mx-auto px-4">
        <h2 className="text-4xl font-bold text-gray-800 mb-12 text-center">Experience</h2>
        <div className="space-y-8">
          {data.map((exp, index) => (
            <div key={exp.id} className="bg-white rounded-lg shadow-md overflow-hidden hover:shadow-lg transition">
              <div className="bg-gradient-to-r from-blue-600 to-blue-400 p-6 text-white">
                <h3 className="text-2xl font-bold">{exp.position}</h3>
                <p className="text-blue-100">{exp.company}</p>
                <p className="text-sm text-blue-100 mt-2">{exp.period}</p>
              </div>
              <div className="p-6">
                <ul className="space-y-3">
                  {exp.description.map((item, idx) => (
                    <li key={idx} className="flex gap-3 text-gray-700">
                      <span className="text-blue-600 font-bold">•</span>
                      <span>{item}</span>
                    </li>
                  ))}
                </ul>
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}

export default Experience;
